 71→    // Report hook count if any
 72→    let hook_count = hook_manager.hook_count();
 73→    if hook_count > 0 && cli.verbose {
 74→        println!("Loaded {} hook(s)", hook_count);
 75→    }
 76→
 77→    let state = StateManager::new(config.state_file.clone());
 78→    let tracker =
 79→        GitTracker::new(&config.project_dir).context("Failed to initialize git tracker")?;
 80→    let runner = ClaudeRunner::new(config.clone());
 81→    let mut audit = AuditLogger::new(&config.audit_dir);
 82→    let mut gate = ApprovalGate::new(cli.auto_approve_threshold, cli.yes);
 83→
 84→    // Determine starting phase
 85→    let start = resolve_start_phase(
 86→        start_phase.as_deref(),
 87→        state.get_last_completed_phase().as_deref(),
 88→    );
 89→
 90→    // Load phases from phases.json if it exists, otherwise use defaults
 91→    let all_phases =
 92→        load_phases_or_default(Some(&config.phases_file)).context("Failed to load phases")?;
 93→
 94→    // Apply permission modes from config to each phase
 95→    let forge_toml = ForgeToml::load_or_default(&forge_dir)
 96→        .context("Failed to load forge.toml configuration")?;
 97→    let phases: Vec<_> = all_phases
 98→        .into_iter()
 99→        .filter(|p| p.number.as_str() >= start.as_str())
100→        .map(|mut p| {
101→            // Get phase settings from config (includes pattern-matched overrides)
102→            let settings = forge_toml.phase_settings(&p.name);
103→            // Apply permission mode from config if phase doesn't have one explicitly set
104→            // (phases.json can override with explicit permission_mode)
105→            if p.permission_mode == PermissionMode::Standard {
106→                p.permission_mode = settings.permission_mode;
107→            }
108→            // Budget is not overridden from config — phases.json is the primary source.
109→            p
110→        })
111→        .collect();
112→    // Create autonomous gate strategy if enabled (config or CLI flag)
113→    let autonomy_enabled = forge_toml.autonomy.enabled || cli.autonomous;
114→    let mut autonomous_strategy = if autonomy_enabled {
115→        Some(AutonomousGateStrategy::new(
116→            forge_toml.autonomy.stale_iterations_before_pivot,
117→            forge_toml.autonomy.pivot_prompt.clone(),
118→        ))
119→    } else {
120→        None
121→    };
122→
123→    let ui = std::sync::Arc::new(OrchestratorUI::new(phases.len() as u64, cli.verbose));
124→
125→    // Start audit run
126→    audit.start_run(RunConfig {
127→        auto_approve_threshold: cli.auto_approve_threshold,
128→        skip_permissions: config.skip_permissions,
129→        verbose: cli.verbose,
130→        spec_file: config.spec_file.clone(),
131→        project_dir: config.project_dir.clone(),
132→    })?;
133→
134→    let mut previous_changes: Option<FileChangeSummary> = None;
135→
136→    for phase in phases {
137→        let phase_span = info_span!("phase",
138→            phase_number = %phase.number,
139→            phase_name = %phase.name,
140→            budget = phase.budget,
141→        );
142→        {
143→            let _enter = phase_span.enter();
144→            info!("Phase started");
145→        }
146→
147→        // Run OnApproval hooks first (can auto-approve/reject)
148→        let approval_result = hook_manager
149→            .run_on_approval(&phase, previous_changes.as_ref())
150→            .await?;
151→
152→        let decision = match approval_result.action {
153→            HookAction::Approve => {
154→                if cli.verbose {
155→                    println!(
156→                        "  {} (hook auto-approved)",
157→                        console::style("Auto-approved").dim()
158→                    );
159→                }
160→                GateDecision::Approved
161→            }
162→            HookAction::Reject => {
163→                if let Some(msg) = &approval_result.message {
164→                    println!("  Hook rejected: {}", msg);
165→                }
166→                GateDecision::Rejected
167→            }
168→            HookAction::Block => {
169→                if let Some(msg) = &approval_result.message {
170→                    println!("  Hook blocked: {}", msg);
171→                }
172→                audit.finish_run()?;
173→                return Ok(());
174→            }
175→            _ => {
176→                if autonomous_strategy.is_some() {
177→                    // Autonomous mode: auto-approve all phases
178→                    GateDecision::Approved
179→                } else {
180→                    // Interactive: use normal approval gate
181→                    gate.check_phase(&phase, previous_changes.as_ref(), &ui)?
182→                }
183→            }
184→        };
185→
186→        match decision {
187→            GateDecision::Aborted => {
188→                println!("Orchestrator aborted by user");
189→                audit.finish_run()?;
190→                return Ok(());
191→            }
192→            GateDecision::Rejected => {
193→                println!("Phase {} skipped", phase.number);
194→                continue;
195→            }
196→            GateDecision::Approved | GateDecision::ApprovedAll => {}
197→        }
198→
199→        // Run PrePhase hooks
200→        let pre_phase_result = hook_manager
201→            .run_pre_phase(&phase, previous_changes.as_ref())
202→            .await?;
203→
204→        match pre_phase_result.action {
205→            HookAction::Block => {
206→                if let Some(msg) = &pre_phase_result.message {
207→                    println!("  PrePhase hook blocked: {}", msg);
208→                }
209→                audit.finish_run()?;
210→                return Ok(());
211→            }
212→            HookAction::Skip => {
213→                if let Some(msg) = &pre_phase_result.message {
214→                    println!("  PrePhase hook skipped phase: {}", msg);
215→                }
216→                continue;
217→            }
218→            _ => {}
219→        }
220→
221→        ui.start_phase(&phase.number, &phase.name);
222→        state.save(&phase.number, 0, "started")?;
223→
224→        let mut phase_audit = PhaseAudit::new(&phase.number, &phase.name, &phase.promise);
225→
226→        // Take git snapshot before phase
227→        let snapshot_sha = tracker.snapshot_before(&phase.number)?;
228→
229→        // Initialize progress tracker for autonomous mode
230→        let mut progress_tracker = ProgressTracker::new();
231→
232→        // Initialize compaction manager for this phase
233→        let context_limit = cli
234→            .context_limit
235→            .clone()
236→            .unwrap_or_else(|| forge_toml.phase_settings(&phase.name).context_limit);
237→        let mut compaction_manager = CompactionManager::new(
238→            &phase.number,
239→            &phase.name,
240→            &phase.promise,
241→            &context_limit,
242→            DEFAULT_MODEL_WINDOW_CHARS,
243→        );
244→
245→        // Track current prompt context (compaction summary if any)
246→        let mut current_prompt_context: Option<PromptContext> = None;
247→
248→        // Session continuity: track active session ID for --resume across iterations
249→        let mut active_session_id: Option<String> = None;
250→        // Iteration feedback: track feedback to inject via --append-system-prompt
251→        let mut previous_feedback: Option<String> = None;
252→
253→        // Check if session continuity and iteration feedback are enabled
254→        let session_continuity_enabled = forge_toml.claude.session_continuity;
255→        let iteration_feedback_enabled = forge_toml.claude.iteration_feedback;
256→
257→        let mut completed = false;
258→        let mut phase_aborted = false;
259→        // Accumulators for budget-exhaustion diagnostics
260→        let mut total_blockers_raised: usize = 0;
261→        let mut any_progress_signaled = false;
262→        let mut total_pivots: usize = 0;
263→        for iter in 1..=phase.budget {
264→            let _iter_span = info_span!("iteration", iteration = iter, budget = phase.budget,);
265→
266→            // === AUTONOMOUS MODE: Check progress before continuing ===
267→            if phase.permission_mode == PermissionMode::Autonomous && iter > 1 {
268→                if let Some(ref mut auto_strategy) = autonomous_strategy {
269→                    let pivot_was_issued = auto_strategy.stale_handler.pivot_issued;
270→                    match auto_strategy.check_stale_progress(&phase, &mut progress_tracker) {
271→                        IterationDecision::StopPhase => {
272→                            println!("  Phase stopped: no progress after pivot");
273→                            break;
274→                        }
275→                        IterationDecision::Continue
276→                            if !pivot_was_issued && auto_strategy.stale_handler.pivot_issued =>
277→                        {
278→                            // Pivot was just issued — inject prompt
279→                            previous_feedback = Some(auto_strategy.pivot_prompt().to_string());
280→                        }
281→                        _ => {}
282→                    }
283→                } else if !gate.check_autonomous_progress(&progress_tracker) {
284→                    // Interactive fallback
285→                    match gate.prompt_no_progress()? {
286→                        IterationDecision::Continue => {
287→                            progress_tracker.stale_iterations = 0;
288→                        }
289→                        IterationDecision::StopPhase => {
290→                            println!("  Phase stopped due to no progress");
291→                            break;
292→                        }
293→                        IterationDecision::Abort => {
294→                            println!("  Orchestrator aborted by user");
295→                            phase_aborted = true;
296→                            break;
297→                        }
298→                        IterationDecision::Skip => {
299→                            continue;
300→                        }
301→                    }
302→                }
303→            }
304→
305→            // Run PreIteration hooks
306→            let pre_iter_result = hook_manager.run_pre_iteration(&phase, iter).await?;
307→
308→            match pre_iter_result.action {
309→                HookAction::Block => {
310→                    if let Some(msg) = &pre_iter_result.message {
311→                        println!("  PreIteration hook blocked: {}", msg);
312→                    }
313→                    break;
314→                }
315→                HookAction::Skip => {
316→                    if let Some(msg) = &pre_iter_result.message {
317→                        println!("  PreIteration hook skipped iteration: {}", msg);
318→                    }
319→                    continue;
320→                }
321→                _ => {}
322→            }
323→
324→            ui.start_iteration(iter, phase.budget);
325→
326→            // Check if compaction is needed before this iteration
327→            if let Some(summary_text) = compaction_manager.compact_if_needed() {
328→                if cli.verbose {
329→                    println!("  Context compacted: {}", compaction_manager.status());
330→                }
331→                // Record compaction in audit
332→                if let Some(compaction) = compaction_manager.last_compaction() {
333→                    phase_audit.add_compaction_event(
334→                        compaction.iterations_summarized,
335→                        compaction.original_chars,
336→                        compaction.summary_chars,
337→                    );
338→                }
339→                current_prompt_context = Some(PromptContext::with_compaction(summary_text));
340→                // Reset session on compaction — the compacted context replaces history
341→                active_session_id = None;
342→                previous_feedback = None;
343→            }
344→
345→            // Run iteration with optional compaction context, session resumption, and feedback
346→            let result = runner
347→                .run_iteration_with_context(
348→                    &phase,
349→                    iter,
350→                    Some(ui.clone()),
351→                    current_prompt_context.as_ref(),
352→                    if session_continuity_enabled {
353→                        active_session_id.as_deref()
354→                    } else {
355→                        None
356→                    },
357→                    if iteration_feedback_enabled {
358→                        previous_feedback.as_deref()
359→                    } else {
360→                        None
361→                    },
362→                )
363→                .await?;
364→
365→            // Compute changes
366→            let changes = tracker.compute_changes(&snapshot_sha)?;
367→            ui.update_files(&changes);
368→
369→            // === READONLY MODE: Validate no modifications ===
370→            if phase.permission_mode == PermissionMode::Readonly
371→                && let Err(e) = gate.validate_readonly_changes(&phase, &changes)
372→            {
373→                println!("  {} {}", console::style("Error:").red().bold(), e);
374→                ui.phase_failed(&phase.number, "readonly mode violation");
375→                phase_audit.finish(
376→                    PhaseOutcome::Error {
377→                        message: e.to_string(),
378→                    },
379→                    changes.clone(),
380→                );
381→                break;
382→            }
383→
384→            // Show individual file changes
385→            for path in &changes.files_added {
386→                ui.show_file_change(path, forge::audit::ChangeType::Added);
387→            }
388→            for path in &changes.files_modified {
389→                ui.show_file_change(path, forge::audit::ChangeType::Modified);
390→            }
391→
392→            // Accumulate cross-iteration signal diagnostics for budget-exhaustion reporting
393→            total_blockers_raised += result.signals.blockers.len();
394→            if result.signals.latest_progress().is_some() {
395→                any_progress_signaled = true;
396→            }
397→            total_pivots += result.signals.pivots.len();
398→
399→            // Update progress tracker for autonomous mode
400→            let progress_pct = result.signals.latest_progress();
401→            progress_tracker.update(&changes, progress_pct);
402→
403→            // Capture session ID for --resume in next iteration
404→            if let Some(ref sid) = result.session.session_id {
405→                active_session_id = Some(sid.clone());
406→            }
407→
408→            // Build iteration feedback for next iteration
409→            previous_feedback = IterationFeedback::new()
410→                .with_iteration_status(iter, phase.budget, result.promise_found)
411→                .with_git_changes(&changes)
412→                .with_signals(&result.signals)
413→                .build();
414→
415→            // Record iteration in compaction manager
416→            let output_summary = extract_output_summary(&result.output, 100);
417→            compaction_manager.record_iteration(
418→                iter,
419→                result.session.prompt_chars,
420→                result.session.output_chars,
421→                &changes,
422→                &result.signals,
423→                &output_summary,
424→            );
425→
426→            // Show context status in verbose mode
427→            if cli.verbose && iter > 1 {
428→                println!("  {}", compaction_manager.status());
429→            }
430→
431→            // Run PostIteration hooks with signals
432→            let post_iter_result = hook_manager
433→                .run_post_iteration_with_signals(
434→                    &phase,
435→                    iter,
436→                    &changes,
437→                    result.promise_found,
438→                    Some(&result.output),
439→                    &result.signals,
440→                )
441→                .await?;
442→
443→            // Handle blockers - pause and prompt user if there are unacknowledged blockers
444→            if result.signals.has_unacknowledged_blockers() {
445→                let blockers = result.signals.unacknowledged_blockers();
446→                for blocker in &blockers {
447→                    ui.show_blocker(&blocker.description);
448→                }
449→
450→                // Auto-continue if --yes flag is set
451→                let continue_anyway = if cli.yes {
452→                    println!(
453→                        "  {} {} blocker(s) detected, auto-continuing (--yes flag)",
454→                        console::style("⚠").yellow(),
455→                        blockers.len()
456→                    );
457→                    true
458→                } else {
459→                    // Prompt user about blockers
460→                    use dialoguer::Confirm;
461→                    match Confirm::new()
462→                        .with_prompt(format!(
463→                            "{} blocker(s) detected. Continue anyway?",
464→                            blockers.len()
465→                        ))
466→                        .default(false)
467→                        .interact()
468→                    {
469→                        Ok(answer) => answer,
470→                        Err(e) => {
471→                            warn!(
472→                                "Could not display blocker confirmation dialog: {}. \
473→                                 Stopping. Re-run with --yes to auto-continue past blockers.",
474→                                e
475→                            );
476→                            false
477→                        }
478→                    }
479→                };
480→
481→                if !continue_anyway {
482→                    ui.phase_failed(&phase.number, "User stopped due to blockers");
483→                    phase_audit.finish(PhaseOutcome::UserAborted, changes.clone());
484→                    break;
485→                }
486→            }
487→
488→            // PostIteration hook can override promise detection
489→            let should_complete = match post_iter_result.action {
490→                HookAction::Block => {
491→                    if let Some(msg) = &post_iter_result.message {
492→                        println!("  PostIteration hook blocked: {}", msg);
493→                    }
494→                    false
495→                }
496→                _ => result.promise_found,
497→            };
498→
499→            if should_complete {
500→                {
501→                    let _enter = _iter_span.enter();
502→                    info!(
503→                        outcome = "completed",
504→                        iterations_used = iter,
505→                        "Phase completed"
506→                    );
507→                }
508→                ui.iteration_success(iter);
509→                phase_audit.finish(PhaseOutcome::Completed { iteration: iter }, changes.clone());
510→                state.save(&phase.number, iter, "completed")?;
511→                previous_changes = Some(changes);
512→                completed = true;
513→                break;
514→            } else {
515→                // Show progress if available
516→                if let Some(pct) = result.signals.latest_progress() {
517→                    ui.iteration_bar_message(iter, phase.budget, &format!("{}% done", pct));
518→                }
519→                ui.iteration_continue(iter);
520→            }
521→
522→            tokio::time::sleep(tokio::time::Duration::from_secs(2)).await;
523→        }
524→
525→        // Handle phase abort (exit orchestrator entirely)
526→        if phase_aborted {
527→            audit.finish_run()?;
528→            return Ok(());
529→        }
530→
531→        if !completed {
532→            let changes = tracker.compute_changes(&snapshot_sha)?;
533→
534→            // Run OnFailure hooks
535→            let failure_result = hook_manager
536→                .run_on_failure(&phase, phase.budget, &changes)
537→                .await?;
538→
539→            if let Some(msg) = &failure_result.message {
540→                println!("  OnFailure hook: {}", msg);
541→            }
542→
543→            phase_audit.finish(PhaseOutcome::MaxIterationsReached, changes);
544→            state.save(&phase.number, phase.budget, "max_iterations")?;
545→            {
546→                let _enter = phase_span.enter();
547→                warn!(outcome = "max_iterations_reached", "Phase exhausted budget");
548→            }
549→            ui.phase_failed(&phase.number, "max iterations reached");
550→
551→            // Actionable budget-exhaustion summary
552→            println!();
553→            println!(
554→                "  {} Phase '{}' exhausted its budget of {} iteration(s) without emitting the promise tag '{}'.",
555→                console::style("Budget exhausted:").red().bold(),
556→                phase.name,
557→                phase.budget,
558→                phase.promise,
559→            );
560→            // Summarize what signals were observed across the whole phase
561→            let progress_note = if any_progress_signaled {
562→                "progress was signaled at least once".to_string()
563→            } else {
564→                "no <progress> signals were ever emitted".to_string()
565→            };
566→            let blockers_note = blocker_note(total_blockers_raised);
567→            let pivots_note = pivot_note(total_pivots);
568→            println!("  Summary: {progress_note}; {blockers_note}; {pivots_note}.");
569→            println!(
570→                "  Tip: Verify the promise tag in your phases config matches exactly \
571→                (case-sensitive). Run 'forge audit --last' to inspect Claude's raw output."
572→            );
573→            println!(
574→                "  Tip: Use <progress>N%</progress> and <blocker>reason</blocker> tags \
575→                in your phase prompt to help diagnose stuck phases."
576→            );
577→        } else {
578→            // Run PostPhase hooks
579→            let post_phase_result = hook_manager
580→                .run_post_phase(
581→                    &phase,
582→                    phase.budget,
583→                    previous_changes
584→                        .as_ref()
585→                        .unwrap_or(&FileChangeSummary::default()),
586→                    true,
587→                )
588→                .await?;
589→
590→            if let Some(msg) = &post_phase_result.message
591→                && cli.verbose
592→            {
593→                println!("  PostPhase hook: {}", msg);
594→            }
595→
596→            ui.phase_complete(&phase.number);
597→        }
598→
599→        audit.add_phase(phase_audit)?;
600→
601→        tokio::time::sleep(tokio::time::Duration::from_secs(5)).await;
602→    }
603→
604→    let run_file = audit.finish_run()?;
605→    println!("Audit log saved to: {}", run_file.display());
606→
607→    Ok(())
608→}
