610→/// Build a human-readable note for the number of blockers raised during a phase.
611→///
612→/// Returns a string like "3 blockers raised" or "no blockers raised".
613→/// This is pure logic that can be unit-tested without external processes.
614→pub fn blocker_note(total_blockers_raised: usize) -> String {
615→    if total_blockers_raised > 0 {
616→        format!(
617→            "{} blocker{} raised",
618→            total_blockers_raised,
619→            if total_blockers_raised == 1 { "" } else { "s" }
620→        )
621→    } else {
622→        "no blockers raised".to_string()
623→    }
624→}
625→
626→/// Build a human-readable note for the number of pivots signaled during a phase.
627→///
628→/// Returns a string like "2 pivots signaled" or "no pivots signaled".
629→/// This is pure logic that can be unit-tested without external processes.
630→pub fn pivot_note(total_pivots: usize) -> String {
631→    if total_pivots > 0 {
632→        format!(
633→            "{} pivot{} signaled",
634→            total_pivots,
635→            if total_pivots == 1 { "" } else { "s" }
636→        )
637→    } else {
638→        "no pivots signaled".to_string()
639→    }
640→}
641→
642→/// Resolve the phase start string from an optional user-supplied value and
643→/// last-completed state.
644→///
645→/// - If `start_phase` is `Some(s)`, that string is returned directly.
646→/// - Otherwise the next phase after `last_completed` is returned (zero-padded
647→///   to two digits), falling back to `"01"` when nothing has been completed.
648→///
649→/// This is pure logic that can be unit-tested without external processes.
650→pub fn resolve_start_phase(start_phase: Option<&str>, last_completed: Option<&str>) -> String {
651→    start_phase.map(|s| s.to_string()).unwrap_or_else(|| {
652→        last_completed
653→            .map(|p| format!("{:02}", p.parse::<u32>().unwrap_or(0) + 1))
654→            .unwrap_or_else(|| "01".to_string())
655→    })
656→}
