658→pub async fn run_single_phase(cli: &Cli, project_dir: PathBuf, phase_num: &str) -> Result<()> {
659→    use forge::init::get_forge_dir;
660→    use forge::phase::PhasesFile;
661→
662→    check_run_prerequisites(&project_dir)?;
663→
664→    // Load phases from phases.json
665→    let forge_dir = get_forge_dir(&project_dir);
666→    let phases_file = forge_dir.join("phases.json");
667→    let pf = PhasesFile::load(&phases_file)?;
668→
669→    let phase = pf
670→        .phases
671→        .into_iter()
672→        .find(|p| p.number == phase_num)
673→        .ok_or_else(|| anyhow::anyhow!("Unknown phase: {}", phase_num))?;
674→
675→    run_orchestrator(cli, project_dir, Some(phase.number)).await
676→}
