  1→//! Integration between the orchestrator and the review system.
  2→//!
  3→//! This module provides the bridge between phase execution and review dispatch,
  4→//! enabling quality gates after phase completion.
  5→//!
  6→//! ## Usage
  7→//!
  8→//! ```no_run
  9→//! use forge::orchestrator::review_integration::{ReviewIntegration, ReviewIntegrationConfig};
 10→//! use forge::phase::Phase;
 11→//!
 12→//! # async fn example() -> anyhow::Result<()> {
 13→//! let config = ReviewIntegrationConfig::default();
 14→//! let integration = ReviewIntegration::new(config);
 15→//!
 16→//! let phase = Phase::new("05", "OAuth", "OAUTH DONE", 10, "reason", vec![]);
 17→//! let files_changed = vec!["src/auth.rs".to_string()];
 18→//!
 19→//! let result = integration.run_phase_reviews(&phase, 5, &files_changed).await?;
 20→//!
 21→//! if result.can_proceed() {
 22→//!     println!("Phase can proceed");
 23→//! }
 24→//! # Ok(())
 25→//! # }
 26→//! ```
 27→
 28→use crate::phase::{Phase, PhaseSpecialistConfig};
 29→use crate::review::{
 30→    DispatchResult, DispatcherConfig, PhaseReviewConfig, ReviewDispatcher, ReviewSpecialist,
 31→    SpecialistType,
 32→};
 33→use anyhow::Result;
 34→use serde::{Deserialize, Serialize};
 35→use std::path::PathBuf;
 36→use std::str::FromStr;
 37→
 38→/// Configuration for review integration with the orchestrator.
 39→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 40→pub struct ReviewIntegrationConfig {
 41→    /// Whether review integration is enabled.
 42→    #[serde(default)]
 43→    pub enabled: bool,
 44→    /// Underlying dispatcher configuration.
 45→    #[serde(default)]
 46→    pub dispatcher: DispatcherConfig,
 47→    /// Default specialists to use if phase has none configured.
 48→    #[serde(default)]
 49→    pub default_specialists: Vec<DefaultSpecialist>,
 50→}
 51→
 52→impl ReviewIntegrationConfig {
 53→    /// Create a new config with reviews enabled.
 54→    pub fn enabled() -> Self {
 55→        Self {
 56→            enabled: true,
 57→            ..Default::default()
 58→        }
 59→    }
 60→
 61→    /// Set the working directory.
 62→    pub fn with_working_dir(mut self, dir: PathBuf) -> Self {
 63→        self.dispatcher = self.dispatcher.with_working_dir(dir);
 64→        self
 65→    }
 66→
 67→    /// Set the Claude command.
 68→    pub fn with_claude_cmd(mut self, cmd: &str) -> Self {
 69→        self.dispatcher = self.dispatcher.with_claude_cmd(cmd);
 70→        self
 71→    }
 72→
 73→    /// Set default specialists.
 74→    pub fn with_default_specialists(mut self, specialists: Vec<DefaultSpecialist>) -> Self {
 75→        self.default_specialists = specialists;
 76→        self
 77→    }
 78→
 79→    /// Enable or disable parallel reviews.
 80→    pub fn with_parallel(mut self, parallel: bool) -> Self {
 81→        self.dispatcher = self.dispatcher.with_parallel(parallel);
 82→        self
 83→    }
 84→
 85→    /// Enable verbose logging.
 86→    pub fn with_verbose(mut self, verbose: bool) -> Self {
 87→        self.dispatcher = self.dispatcher.with_verbose(verbose);
 88→        self
 89→    }
 90→}
 91→
 92→/// Default specialist configuration.
 93→#[derive(Debug, Clone, Serialize, Deserialize)]
 94→pub struct DefaultSpecialist {
 95→    pub specialist_type: SpecialistType,
 96→    pub gate: bool,
 97→}
 98→
 99→impl DefaultSpecialist {
100→    /// Create a gating specialist.
101→    ///
102→    /// The `name` is parsed via [`SpecialistType::from_str`], which recognises all
103→    /// short-form aliases (`"security"`, `"performance"`, etc.) and falls back to
104→    /// `Custom(name)` for unrecognised values.
105→    pub fn gating(name: &str) -> Self {
106→        Self {
107→            specialist_type: SpecialistType::from_str(name)
108→                .unwrap_or_else(|_| SpecialistType::Custom(name.to_string())),
109→            gate: true,
110→        }
111→    }
112→
113→    /// Create an advisory specialist.
114→    ///
115→    /// The `name` is parsed via [`SpecialistType::from_str`], which recognises all
116→    /// short-form aliases (`"security"`, `"performance"`, etc.) and falls back to
117→    /// `Custom(name)` for unrecognised values.
118→    pub fn advisory(name: &str) -> Self {
119→        Self {
120→            specialist_type: SpecialistType::from_str(name)
121→                .unwrap_or_else(|_| SpecialistType::Custom(name.to_string())),
122→            gate: false,
123→        }
124→    }
125→
126→    /// Convert to a ReviewSpecialist.
127→    fn to_review_specialist(&self) -> ReviewSpecialist {
128→        ReviewSpecialist::new(self.specialist_type.clone(), self.gate)
129→    }
130→}
131→
132→/// Integration layer between orchestrator and review system.
133→pub struct ReviewIntegration {
134→    config: ReviewIntegrationConfig,
135→    dispatcher: ReviewDispatcher,
136→}
137→
138→impl ReviewIntegration {
139→    /// Create a new review integration instance.
140→    pub fn new(config: ReviewIntegrationConfig) -> Self {
141→        let dispatcher = ReviewDispatcher::new(config.dispatcher.clone());
142→        Self { config, dispatcher }
143→    }
144→
145→    /// Check if review integration is enabled.
146→    pub fn is_enabled(&self) -> bool {
147→        self.config.enabled
148→    }
149→
150→    /// Run reviews for a completed phase.
151→    ///
152→    /// Returns a DispatchResult indicating whether the phase can proceed.
153→    pub async fn run_phase_reviews(
154→        &self,
155→        phase: &Phase,
156→        iterations_used: u32,
157→        files_changed: &[String],
158→    ) -> Result<DispatchResult> {
159→        if !self.config.enabled {
160→            // Return a successful result if reviews are disabled
161→            return Ok(DispatchResult::success(
162→                crate::review::ReviewAggregation::new(&phase.number),
163→                std::time::Duration::from_secs(0),
164→            ));
165→        }
166→
167→        // Build specialists list
168→        let specialists = self.build_specialists(phase);
169→
170→        if specialists.is_empty() {
171→            // No specialists configured, return success
172→            return Ok(DispatchResult::success(
173→                crate::review::ReviewAggregation::new(&phase.number),
174→                std::time::Duration::from_secs(0),
175→            ));
176→        }
177→
178→        // Build review config
179→        let review_config = PhaseReviewConfig::new(&phase.number, &phase.name)
180→            .add_specialists(specialists)
181→            .with_budget(phase.budget, iterations_used)
182→            .with_files_changed(files_changed.to_vec());
183→
184→        // Run the dispatch
185→        self.dispatcher.dispatch(review_config).await
186→    }
187→
188→    /// Build the list of specialists for a phase.
189→    fn build_specialists(&self, phase: &Phase) -> Vec<ReviewSpecialist> {
190→        // Check if phase has explicit review configuration
191→        if let Some(review_settings) = &phase.reviews
192→            && !review_settings.specialists.is_empty()
193→        {
194→            return review_settings
195→                .specialists
196→                .iter()
197→                .map(Self::phase_config_to_specialist)
198→                .collect();
199→        }
200→
201→        // Fall back to default specialists
202→        self.config
203→            .default_specialists
204→            .iter()
205→            .map(|s| s.to_review_specialist())
206→            .collect()
207→    }
208→
209→    /// Convert a PhaseSpecialistConfig to a ReviewSpecialist.
210→    fn phase_config_to_specialist(config: &PhaseSpecialistConfig) -> ReviewSpecialist {
211→        let mut specialist = ReviewSpecialist::new(config.specialist_type.clone(), config.gate);
212→
213→        if !config.focus_areas.is_empty() {
214→            specialist = specialist.with_focus_areas(config.focus_areas.clone());
215→        }
216→
217→        specialist
218→    }
219→}
220→
221→/// Result of a phase with reviews.
222→#[derive(Debug, Clone)]
223→pub struct PhaseWithReviewResult {
224→    /// Whether the phase itself completed successfully.
225→    pub phase_success: bool,
226→    /// Whether reviews passed (or no reviews were configured).
227→    pub reviews_passed: bool,
228→    /// The dispatch result from reviews.
229→    pub review_result: Option<DispatchResult>,
230→    /// Human-readable summary.
231→    pub summary: String,
232→}
233→
234→impl PhaseWithReviewResult {
235→    /// Create a result for a successful phase without reviews.
236→    pub fn success_no_reviews() -> Self {
237→        Self {
238→            phase_success: true,
239→            reviews_passed: true,
240→            review_result: None,
241→            summary: "Phase completed successfully (no reviews configured)".to_string(),
242→        }
243→    }
244→
245→    /// Create a result for a successful phase with passing reviews.
246→    pub fn success_with_reviews(review_result: DispatchResult) -> Self {
247→        let summary = format!(
248→            "Phase completed, reviews: {} ({} findings)",
249→            review_result.aggregation.overall_verdict(),
250→            review_result.aggregation.all_findings_count()
251→        );
252→        Self {
253→            phase_success: true,
254→            reviews_passed: review_result.can_proceed(),
255→            review_result: Some(review_result),
256→            summary,
257→        }
258→    }
259→
260→    /// Create a result for a failed phase (no reviews run).
261→    pub fn phase_failed(reason: &str) -> Self {
262→        Self {
263→            phase_success: false,
264→            reviews_passed: false,
265→            review_result: None,
266→            summary: format!("Phase failed: {}", reason),
267→        }
268→    }
269→
270→    /// Check if the overall result allows proceeding to the next phase.
271→    pub fn can_proceed(&self) -> bool {
272→        self.phase_success && self.reviews_passed
273→    }
274→
275→    /// Check if reviews need to be fixed before proceeding.
276→    pub fn needs_review_fix(&self) -> bool {
277→        self.review_result.as_ref().is_some_and(|r| r.needs_fix())
278→    }
279→
280→    /// Check if the phase has terminally failed reviews.
281→    pub fn is_phase_failed(&self) -> bool {
282→        self.review_result
283→            .as_ref()
284→            .is_some_and(|r| r.is_phase_failed())
285→    }
286→
287→    /// Get fix instructions if available.
288→    pub fn fix_instructions(&self) -> Option<&str> {
289→        self.review_result
290→            .as_ref()
291→            .and_then(|r| r.fix_instructions())
292→    }
293→}
