100→                .worker_results
101→                .first()
102→                .map(|worker| worker.worker_name.clone());
103→        }
104→
105→        self.worker_results
106→            .iter()
107→            .find(|worker| worker.diff_text == self.winning_diff)
108→            .map(|worker| worker.worker_name.clone())
109→    }
